--
-- Table structure for table `realiza`
--

DROP TABLE IF EXISTS `realiza`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `realiza` (
  `ID` int NOT NULL AUTO_INCREMENT,
  `DNI_PRESO` varchar(9) NOT NULL,
  `NOMBRE_ACTIVIDAD` varchar(50) NOT NULL,
  `NUM_ASISTENCIA` int DEFAULT NULL,
  `FECHA_INICIO` date DEFAULT NULL,
  `FECHA_FIN` date DEFAULT NULL,
  PRIMARY KEY (`ID`),
  KEY `DNI_PRESO` (`DNI_PRESO`),
  KEY `NOMBRE_ACTIVIDAD` (`NOMBRE_ACTIVIDAD`),
  CONSTRAINT `fk_realiza_actividad` FOREIGN KEY (`NOMBRE_ACTIVIDAD`) REFERENCES `actividad` (`NOMBRE_ACTIVIDAD`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_realiza_preso` FOREIGN KEY (`DNI_PRESO`) REFERENCES `preso` (`DNI`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=201 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

